mapper.select:
SELECT DISTINCT bpap.bank_process_id
FROM transactions t
INNER JOIN bank_process_accounting_posted bpap ON bpap.id = t.bank_process_posted_id
WHERE t.tenant_id = #{tenantId}
  AND t.id IN

    #{id}

SELECT x.currencyCode AS currencyCode, COALESCE(SUM(x.bfPart), 0) AS bfAmount FROM ( SELECT UPPER(c.code) AS currencyCode, -t.amount AS bfPart FROM transactions t INNER JOIN currency c ON c.id = t.currency_id AND c.tenant_id = t.tenant_id WHERE t.tenant_id = #{tenantId} AND t.account_id = #{accountId} AND t.bank_process_posted_id IS NULL AND t.approval_status = 'APPROVED' AND t.transaction_type IN () AND AND t.transaction_date < #{dateFrom}
AND UPPER(c.code) IN
UPPER(#{code})
UNION ALL
SELECT UPPER(c.code) AS currencyCode, t.amount AS bfPart FROM transactions t INNER JOIN currency c ON c.id = t.currency_id AND c.tenant_id = t.tenant_id WHERE t.tenant_id = #{tenantId} AND t.from_account_id = #{accountId} AND t.from_account_id IS NOT NULL AND t.bank_process_posted_id IS NULL AND t.approval_status = 'APPROVED' AND t.transaction_type IN () AND AND t.transaction_date < #{dateFrom}
AND UPPER(c.code) IN
UPPER(#{code})
) x GROUP BY x.currencyCode ORDER BY currencyCode ASC

SELECT x.currencyCode AS currencyCode, COALESCE(SUM(x.bfPart), 0) AS bfAmount FROM ( SELECT UPPER(c.code) AS currencyCode, -t.amount AS bfPart FROM transactions t INNER JOIN currency c ON c.id = t.currency_id AND c.tenant_id = t.tenant_id WHERE t.tenant_id = #{tenantId} AND t.account_id = #{accountId} AND t.bank_process_posted_id IS NULL AND t.approval_status = 'APPROVED' AND t.transaction_type = 'PROFIT' AND t.transaction_date < #{dateFrom}
AND UPPER(c.code) IN
UPPER(#{code})
UNION ALL
SELECT UPPER(c.code) AS currencyCode, t.amount AS bfPart FROM transactions t INNER JOIN currency c ON c.id = t.currency_id AND c.tenant_id = t.tenant_id WHERE t.tenant_id = #{tenantId} AND t.from_account_id = #{accountId} AND t.from_account_id IS NOT NULL AND t.bank_process_posted_id IS NULL AND t.approval_status = 'APPROVED' AND t.transaction_type = 'PROFIT' AND t.transaction_date < #{dateFrom}
AND UPPER(c.code) IN
UPPER(#{code})
) x GROUP BY x.currencyCode ORDER BY currencyCode ASC

SELECT x.currencyCode AS currencyCode, COALESCE(SUM(x.bfPart), 0) AS bfAmount FROM ( SELECT UPPER(c.code) AS currencyCode, t.amount AS bfPart FROM transactions t INNER JOIN currency c ON c.id = t.currency_id AND c.tenant_id = t.tenant_id WHERE t.tenant_id = #{tenantId} AND t.account_id = #{accountId} AND t.from_account_id IS NULL AND AND t.bank_process_posted_id IS NULL AND t.approval_status = 'APPROVED' AND t.transaction_type = 'RATE' AND AND t.transaction_date < #{dateFrom}
AND UPPER(c.code) IN
UPPER(#{code})
UNION ALL
SELECT UPPER(c.code) AS currencyCode, -t.amount AS bfPart FROM transactions t INNER JOIN currency c ON c.id = t.currency_id AND c.tenant_id = t.tenant_id WHERE t.tenant_id = #{tenantId} AND t.account_id = #{accountId} AND t.from_account_id IS NOT NULL AND t.bank_process_posted_id IS NULL AND t.approval_status = 'APPROVED' AND t.transaction_type = 'RATE' AND AND t.transaction_date < #{dateFrom}
AND UPPER(c.code) IN
UPPER(#{code})
UNION ALL
SELECT UPPER(c.code) AS currencyCode, t.amount AS bfPart FROM transactions t INNER JOIN currency c ON c.id = t.currency_id AND c.tenant_id = t.tenant_id WHERE t.tenant_id = #{tenantId} AND t.from_account_id = #{accountId} AND t.from_account_id IS NOT NULL AND t.bank_process_posted_id IS NULL AND t.approval_status = 'APPROVED' AND t.transaction_type = 'RATE' AND AND t.transaction_date < #{dateFrom}
AND UPPER(c.code) IN
UPPER(#{code})
) x GROUP BY x.currencyCode ORDER BY currencyCode ASC

SELECT t.id AS id, t.transaction_type AS transactionType, t.created_at AS createdAt, to_a.account_id AS toAccountCode, from_a.account_id AS fromAccountCode, t.amount AS amount, UPPER(c.code) AS currencyCode, t.description AS description, t.remark AS remark, t.created_by AS createdBy, FALSE AS deleted, NULL AS deletedBy, NULL AS deletedAt FROM transactions t INNER JOIN currency c ON c.id = t.currency_id AND c.tenant_id = t.tenant_id INNER JOIN account to_a ON to_a.id = t.account_id LEFT JOIN account from_a ON from_a.id = t.from_account_id WHERE t.tenant_id = #{tenantId} AND t.bank_process_posted_id IS NULL AND t.approval_status = 'APPROVED' AND t.transaction_type IN () AND t.transaction_date >= #{dateFrom} AND t.transaction_date <= #{dateTo}
AND t.transaction_type = #{transactionType}
AND UPPER(c.code) IN
UPPER(#{code})
AND ( UPPER(to_a.account_id) LIKE CONCAT('%', UPPER(#{q}), '%') OR UPPER(COALESCE(from_a.account_id, '')) LIKE CONCAT('%', UPPER(#{q}), '%') OR UPPER(COALESCE(t.description, '')) LIKE CONCAT('%', UPPER(#{q}), '%') OR UPPER(COALESCE(t.remark, '')) LIKE CONCAT('%', UPPER(#{q}), '%') OR UPPER(COALESCE(t.created_by, '')) LIKE CONCAT('%', UPPER(#{q}), '%') )
ORDER BY t.created_at DESC, t.id DESC

SELECT td.transaction_id AS id, td.transaction_type AS transactionType, td.created_at AS createdAt, to_a.account_id AS toAccountCode, from_a.account_id AS fromAccountCode, td.amount AS amount, UPPER(c.code) AS currencyCode, td.description AS description, td.remark AS remark, td.created_by AS createdBy, TRUE AS deleted, td.deleted_by AS deletedBy, td.deleted_at AS deletedAt FROM transactions_deleted td INNER JOIN currency c ON c.id = td.currency_id AND c.tenant_id = td.tenant_id INNER JOIN account to_a ON to_a.id = td.account_id LEFT JOIN account from_a ON from_a.id = td.from_account_id WHERE td.tenant_id = #{tenantId} AND td.bank_process_posted_id IS NULL AND td.transaction_type IN () AND td.transaction_date >= #{dateFrom} AND td.transaction_date <= #{dateTo}
AND td.transaction_type = #{transactionType}
AND UPPER(c.code) IN
UPPER(#{code})
AND ( UPPER(to_a.account_id) LIKE CONCAT('%', UPPER(#{q}), '%') OR UPPER(COALESCE(from_a.account_id, '')) LIKE CONCAT('%', UPPER(#{q}), '%') OR UPPER(COALESCE(td.description, '')) LIKE CONCAT('%', UPPER(#{q}), '%') OR UPPER(COALESCE(td.remark, '')) LIKE CONCAT('%', UPPER(#{q}), '%') OR UPPER(COALESCE(td.created_by, '')) LIKE CONCAT('%', UPPER(#{q}), '%') OR UPPER(COALESCE(td.deleted_by, '')) LIKE CONCAT('%', UPPER(#{q}), '%') )
ORDER BY td.created_at DESC, td.transaction_id DESC
